solutions.javascript:
// Define a function to calculate the column widths
function calculateColumnWidths(itemWidths, gridColumns) {
  // Calculate the total width by summing up all item widths
  let totalWidth = itemWidths.reduce((a, b) => a + b, 0);
  // Calculate the number of columns
  let numColumns = Math.min(gridColumns, itemWidths.length);
  // Calculate the column width by dividing the total width by the number of columns
  let columnWidth = totalWidth / numColumns;
  // Return the column widths
  return Array(numColumns).fill(columnWidth);
}
